import{_ as a,o as i,c as s,a2 as t}from"./chunks/framework.CKCxdkvf.js";const u=JSON.parse('{"title":"RFC-005 — Accessibility: ARIA on canvas screens, reduced-motion contract","description":"","frontmatter":{},"headers":[],"relativePath":"rfc/RFC-005.md","filePath":"rfc/RFC-005.md"}'),o={name:"rfc/RFC-005.md"};function r(n,e,l,c,d,h){return i(),s("div",null,[...e[0]||(e[0]=[t(`<h1 id="rfc-005-—-accessibility-aria-on-canvas-screens-reduced-motion-contract" tabindex="-1">RFC-005 — Accessibility: ARIA on canvas screens, reduced-motion contract <a class="header-anchor" href="#rfc-005-—-accessibility-aria-on-canvas-screens-reduced-motion-contract" aria-label="Permalink to &quot;RFC-005 — Accessibility: ARIA on canvas screens, reduced-motion contract&quot;">​</a></h1><blockquote><p>Status · Decided TA anchor · §constraints · §components Closed by · ADR-025 (2026-04-29) Why this is an RFC · Canvas and WebGL are inherently inaccessible to screen readers. The approach — what gets ARIA roles, what gets keyboard nav, where reduced-motion applies, what&#39;s explicitly deferred — is open with real cost/completeness trade-offs.</p></blockquote><h2 id="the-question" tabindex="-1">The question <a class="header-anchor" href="#the-question" aria-label="Permalink to &quot;The question&quot;">​</a></h2><p>Four of six screens render primarily to canvas or WebGL. Screen readers cannot read canvas content. What level of accessibility is achievable without rewriting the rendering architecture, and where does v1 draw the line?</p><h2 id="use-cases" tabindex="-1">Use cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to &quot;Use cases&quot;">​</a></h2><ul><li>Keyboard user navigating the mission library card grid</li><li>Screen reader user accessing mission information via detail panels</li><li>User with <code>prefers-reduced-motion</code> on solar system explorer or fly screen</li><li>Keyboard user navigating between screens via the nav bar</li></ul><h2 id="goals" tabindex="-1">Goals <a class="header-anchor" href="#goals" aria-label="Permalink to &quot;Goals&quot;">​</a></h2><ul><li>Nav bar fully keyboard-navigable with visible focus indicators</li><li>Detail panel HTML content is screen-reader accessible</li><li>Mission library keyboard-navigable</li><li><code>prefers-reduced-motion</code> stops/slows Three.js animations and canvas loops</li><li>Documented honestly: canvas rendering is not accessible in v1</li></ul><h2 id="constraints" tabindex="-1">Constraints <a class="header-anchor" href="#constraints" aria-label="Permalink to &quot;Constraints&quot;">​</a></h2><p>Canvas and WebGL are opaque to screen readers. Full accessibility would require a parallel DOM structure mirroring canvas state — out of scope for v1.</p><h2 id="proposed-approach" tabindex="-1">Proposed approach <a class="header-anchor" href="#proposed-approach" aria-label="Permalink to &quot;Proposed approach&quot;">​</a></h2><p><strong>Tier 1 — v1:</strong></p><ul><li>Nav bar: <code>role=&quot;navigation&quot;</code>, <code>aria-label=&quot;Main navigation&quot;</code>, focus rings visible</li><li>Detail panels: semantic headings, <code>role=&quot;complementary&quot;</code>, focus management on open/close</li><li>Mission library: cards as <code>&lt;button&gt;</code> elements with accessible text, arrow-key navigation</li><li><code>prefers-reduced-motion</code>: <code>matchMedia</code> detection, stops auto-orbit in 3D, reduces simSpeed in 2D</li></ul><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> reducedMotion</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> window.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">matchMedia</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;(prefers-reduced-motion: reduce)&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">).matches;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// In animate: if reducedMotion, skip auto-orbit, halve simSpeed multiplier</span></span></code></pre></div><p><strong>Tier 2 — deferred to v2:</strong></p><ul><li>Canvas object keyboard navigation (select a planet by keyboard)</li><li>Full screen reader description of canvas content</li><li>High-contrast mode</li></ul><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><p><strong>Full WCAG 2.1 AA on canvas</strong> — requires parallel accessible DOM; multiplies development cost; architecturally complex. Not feasible for v1.</p><p><strong>No accessibility in v1</strong> — the nav bar and mission library are HTML-based; these are low-cost wins with real user impact. Skipping entirely is not justified.</p><p><strong>Third-party a11y library</strong> — adds a dependency; scope is narrow enough to implement without one.</p><h2 id="trade-offs" tabindex="-1">Trade-offs <a class="header-anchor" href="#trade-offs" aria-label="Permalink to &quot;Trade-offs&quot;">​</a></h2><p>Tier 1 covers HTML-based parts (nav, panels, library) and the reduced-motion contract. Canvas and WebGL screens remain inaccessible to screen readers. This is documented honestly in the README.</p><h2 id="open-questions" tabindex="-1">Open questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open questions&quot;">​</a></h2><ol><li>Should canvas screens have an <code>aria-label</code> describing what they contain (&quot;Interactive 3D solar system. Use the detail panels for screen reader access.&quot;)?</li><li>Is <code>prefers-reduced-motion</code> sufficient for Three.js, or do screens need their own reduced-motion flags?</li><li>What&#39;s the minimum focus-ring visibility requirement on the dark-themed UI?</li></ol><h2 id="closing-evidence" tabindex="-1">Closing evidence <a class="header-anchor" href="#closing-evidence" aria-label="Permalink to &quot;Closing evidence&quot;">​</a></h2><p>Nav bar keyboard-navigable, detail panels screen-reader accessible, mission library keyboard-navigable, <code>prefers-reduced-motion</code> stops auto-orbit and canvas animations. All six screens. Available at Slice 6 gate.</p><h2 id="how-this-closes" tabindex="-1">How this closes <a class="header-anchor" href="#how-this-closes" aria-label="Permalink to &quot;How this closes&quot;">​</a></h2><p>One ADR: the accessibility contract for v1 — what is covered, what is explicitly deferred, reduced-motion implementation pattern.</p>`,28)])])}const b=a(o,[["render",r]]);export{u as __pageData,b as default};
